func splayOp(root *snode, key int) *snode {
	if root == nil || root.key == key {
		return root
	}
	if key < root.key {
		if root.left == nil {
			return root
		}
		if key < root.left.key {
			root.left.left = splayOp(root.left.left, key)
			root = rightRotate(root)
		} else if key > root.left.key {
			root.left.right = splayOp(root.left.right, key)
			if root.left.right != nil {
				root.left = leftRotate(root.left)
			}
		}
		if root.left == nil {
			return root
		}
		return rightRotate(root)
	}
	if root.right == nil {
		return root
	}
	if key > root.right.key {
		root.right.right = splayOp(root.right.right, key)
		root = leftRotate(root)
	} else if key < root.right.key {
		root.right.left = splayOp(root.right.left, key)
		if root.right.left != nil {
			root.right = rightRotate(root.right)
		}
	}
	if root.right == nil {
		return root
	}
	return leftRotate(root)
}

func insertNode(root *snode, key int) *snode {
	if root == nil {
		return &snode{key: key}
	}
	root = splayOp(root, key)
	if root.key == key {
		return root
	}
	node := &snode{key: key}
	if key < root.key {
		node.right = root
		node.left = root.left
		root.left = nil
	} else {
		node.left = root
		node.right = root.right
		root.right = nil
	}
	return node
}

func inorder(node *snode, result *[]int) {
	if node == nil {
		return
	}
	inorder(node.left, result)
	*result = append(*result, node.key)
	inorder(node.right, result)
}

// SplayTree inserts values into a splay tree and returns sorted inorder traversal.
func SplayTree(arr []int) []int {
	var root *snode
	for _, val := range arr {
		root = insertNode(root, val)
	}
	result := []int{}
	inorder(root, &result)
	return result
}

import java.util.ArrayList;
import java.util.List;

public class SplayTree {
    static class Node {
        int key;
        Node left, right;
        Node(int key) { this.key = key; }
    }

    private static Node rightRotate(Node x) {
        Node y = x.left;
        x.left = y.right;
        y.right = x;
        return y;
    }

    private static Node leftRotate(Node x) {
        Node y = x.right;
        x.right = y.left;
        y.left = x;
        return y;
    }

    private static Node splay(Node root, int key) {
        if (root == null || root.key == key) return root;
        if (key < root.key) {
            if (root.left == null) return root;
            if (key < root.left.key) {
                root.left.left = splay(root.left.left, key);
                root = rightRotate(root);
            } else if (key > root.left.key) {
                root.left.right = splay(root.left.right, key);
                if (root.left.right != null) root.left = leftRotate(root.left);
            }
            return root.left == null ? root : rightRotate(root);
        } else {
            if (root.right == null) return root;
            if (key > root.right.key) {
                root.right.right = splay(root.right.right, key);
                root = leftRotate(root);
            } else if (key < root.right.key) {
                root.right.left = splay(root.right.left, key);
                if (root.right.left != null) root.right = rightRotate(root.right);
            }
            return root.right == null ? root : leftRotate(root);
        }
    }

    private static Node insert(Node root, int key) {
        if (root == null) return new Node(key);
        root = splay(root, key);
        if (root.key == key) return root;
        Node node = new Node(key);
        if (key < root.key) {
            node.right = root;
            node.left = root.left;
            root.left = null;
        } else {
            node.left = root;
            node.right = root.right;
            root.right = null;
        }
        return node;
    }

    private static void inorder(Node node, List<Integer> result) {
        if (node == null) return;
        inorder(node.left, result);
        result.add(node.key);
        inorder(node.right, result);
    }

    public static int[] splayTree(int[] arr) {
        Node root = null;
        for (int val : arr) root = insert(root, val);
        List<Integer> result = new ArrayList<>();
        inorder(root, result);
        return result.stream().mapToInt(Integer::intValue).toArray();
    }
}

private class SNode(val key: Int) {
    var left: SNode? = null
    var right: SNode? = null
}

private fun rightRotate(x: SNode): SNode {
    val y = x.left!!
    x.left = y.right
    y.right = x
    return y
}

private fun leftRotate(x: SNode): SNode {
    val y = x.right!!
    x.right = y.left
    y.left = x
    return y
}

private fun splayOp(root: SNode?, key: Int): SNode? {
    if (root == null || root.key == key) return root
    if (key < root.key) {
        if (root.left == null) return root
        if (key < root.left!!.key) {
            root.left!!.left = splayOp(root.left!!.left, key)
            val r = rightRotate(root)
            return if (r.left == null) r else r
        } else if (key > root.left!!.key) {
            root.left!!.right = splayOp(root.left!!.right, key)
            if (root.left!!.right != null) root.left = leftRotate(root.left!!)
        }
        return if (root.left == null) root else rightRotate(root)
    } else {
        if (root.right == null) return root
        if (key > root.right!!.key) {
            root.right!!.right = splayOp(root.right!!.right, key)
            val r = leftRotate(root)
            return if (r.right == null) r else r
        } else if (key < root.right!!.key) {
            root.right!!.left = splayOp(root.right!!.left, key)
            if (root.right!!.left != null) root.right = rightRotate(root.right!!)
        }
        return if (root.right == null) root else leftRotate(root)
    }
}

private fun insertNode(root: SNode?, key: Int): SNode {
    if (root == null) return SNode(key)
    val r = splayOp(root, key)!!
    if (r.key == key) return r
    val node = SNode(key)
    if (key < r.key) {
        node.right = r
        node.left = r.left
        r.left = null
    } else {
        node.left = r
        node.right = r.right
        r.right = null
    }
    return node
}

private fun inorderCollect(node: SNode?, result: MutableList<Int>) {
    if (node == null) return
    inorderCollect(node.left, result)
    result.add(node.key)
    inorderCollect(node.right, result)
}

