def splay_tree(arr: list[int]) -> list[int]:
    class Node:
        def __init__(self, key):
            self.key = key
            self.left = None
            self.right = None

    def right_rotate(x):
        y = x.left
        x.left = y.right
        y.right = x
        return y

    def left_rotate(x):
        y = x.right
        x.right = y.left
        y.left = x
        return y

    def splay(root, key):
        if root is None or root.key == key:
            return root
        if key < root.key:
            if root.left is None:
                return root
            if key < root.left.key:
                root.left.left = splay(root.left.left, key)
                root = right_rotate(root)
            elif key > root.left.key:
                root.left.right = splay(root.left.right, key)
                if root.left.right:
                    root.left = left_rotate(root.left)
            return root if root.left is None else right_rotate(root)
        else:
            if root.right is None:
                return root
            if key > root.right.key:
                root.right.right = splay(root.right.right, key)
                root = left_rotate(root)
            elif key < root.right.key:
                root.right.left = splay(root.right.left, key)
                if root.right.left:
                    root.right = right_rotate(root.right)
            return root if root.right is None else left_rotate(root)

    def insert(root, key):
        if root is None:
            return Node(key)
        root = splay(root, key)
        if root.key == key:
            return root
        new_node = Node(key)
        if key < root.key:
            new_node.right = root
            new_node.left = root.left
            root.left = None
        else:
            new_node.left = root
            new_node.right = root.right
            root.right = None
        return new_node

    def inorder(node, result):
        if node is None:
            return
        inorder(node.left, result)
        result.append(node.key)
        inorder(node.right, result)

    root = None
    for val in arr:
        root = insert(root, val)

    result = []
    inorder(root, result)
    return result

type Link = Option<Box<SNode>>;

struct SNode {
    key: i32,
    left: Link,
    right: Link,
}

impl SNode {
    fn new(key: i32) -> Self {
        SNode { key, left: None, right: None }
    }
}

fn right_rotate(mut x: Box<SNode>) -> Box<SNode> {
    let mut y = x.left.take().unwrap();
    x.left = y.right.take();
    y.right = Some(x);
    y
}

fn left_rotate(mut x: Box<SNode>) -> Box<SNode> {
    let mut y = x.right.take().unwrap();
    x.right = y.left.take();
    y.left = Some(x);
    y
}

fn splay_op(root: Link, key: i32) -> Link {
    let mut root = match root {
        None => return None,
        Some(r) => r,
    };
    if root.key == key {
        return Some(root);
    }
    if key < root.key {
        if root.left.is_none() {
            return Some(root);
        }
        let mut left = root.left.take().unwrap();
        if key < left.key {
            left.left = splay_op(left.left.take(), key);
            root.left = Some(left);
            root = right_rotate(root);
        } else if key > left.key {
            left.right = splay_op(left.right.take(), key);
            if left.right.is_some() {
                let rotated = left_rotate(left);
                root.left = Some(rotated);
            } else {
                root.left = Some(left);
            }
        } else {
            root.left = Some(left);
        }
        if root.left.is_some() {
            Some(right_rotate(root))
        } else {
            Some(root)
        }
    } else {
        if root.right.is_none() {
            return Some(root);
        }
        let mut right = root.right.take().unwrap();
        if key > right.key {
            right.right = splay_op(right.right.take(), key);
            root.right = Some(right);
            root = left_rotate(root);
        } else if key < right.key {
            right.left = splay_op(right.left.take(), key);
            if right.left.is_some() {
                let rotated = right_rotate(right);
                root.right = Some(rotated);
            } else {
                root.right = Some(right);
            }
        } else {
            root.right = Some(right);
        }
        if root.right.is_some() {
            Some(left_rotate(root))
        } else {
            Some(root)
        }
    }
}

fn insert_node(root: Link, key: i32) -> Box<SNode> {
    match root {
        None => Box::new(SNode::new(key)),
        Some(r) => {
            let mut r = splay_op(Some(r), key).unwrap();
            if r.key == key {
                return r;
            }
            let mut node = Box::new(SNode::new(key));
            if key < r.key {
                node.left = r.left.take();
                node.right = Some(r);
            } else {
                node.right = r.right.take();
                node.left = Some(r);
            }
            node
        }
    }
}

fn inorder(node: &Link, result: &mut Vec<i32>) {
    if let Some(ref n) = node {
        inorder(&n.left, result);
        result.push(n.key);
        inorder(&n.right, result);
    }
}

pub fn splay_tree(arr: &[i32]) -> Vec<i32> {
    let mut root: Link = None;
    for &val in arr {
        root = Some(insert_node(root, val));
    }
    let mut result = Vec::new();
    inorder(&root, &mut result);
    result
}

object SplayTree {
  private class SNode(val key: Int, var left: SNode = null, var right: SNode = null)

  private def rightRotate(x: SNode): SNode = {
    val y = x.left
    x.left = y.right
    y.right = x
    y
  }

  private def leftRotate(x: SNode): SNode = {
    val y = x.right
    x.right = y.left
    y.left = x
    y
  }

  private def splayOp(root: SNode, key: Int): SNode = {
    if (root == null || root.key == key) return root
    if (key < root.key) {
      if (root.left == null) return root
      if (key < root.left.key) {
        root.left.left = splayOp(root.left.left, key)
        val r = rightRotate(root)
        return r
      } else if (key > root.left.key) {
        root.left.right = splayOp(root.left.right, key)
        if (root.left.right != null) root.left = leftRotate(root.left)
      }
      if (root.left == null) root else rightRotate(root)
    } else {
      if (root.right == null) return root
      if (key > root.right.key) {
        root.right.right = splayOp(root.right.right, key)
        val r = leftRotate(root)
        return r
      } else if (key < root.right.key) {
        root.right.left = splayOp(root.right.left, key)
        if (root.right.left != null) root.right = rightRotate(root.right)
      }
      if (root.right == null) root else leftRotate(root)
    }
  }

  private def insertNode(root: SNode, key: Int): SNode = {
    if (root == null) return new SNode(key)
    val r = splayOp(root, key)
    if (r.key == key) return r
    val node = new SNode(key)
    if (key < r.key) {
      node.right = r
      node.left = r.left
      r.left = null
    } else {
      node.left = r
      node.right = r.right
      r.right = null
    }
    node
  }

  private def inorderCollect(node: SNode, result: scala.collection.mutable.ArrayBuffer[Int]): Unit = {
    if (node == null) return
    inorderCollect(node.left, result)
    result += node.key
    inorderCollect(node.right, result)
  }

  def splayTree(arr: Array[Int]): Array[Int] = {
    var root: SNode = null
    for (v <- arr) root = insertNode(root, v)
    val result = scala.collection.mutable.ArrayBuffer[Int]()
    inorderCollect(root, result)
    result.toArray
  }
}

private class SNode {
    var key: Int
    var left: SNode?
    var right: SNode?
    init(_ key: Int) { self.key = key; self.left = nil; self.right = nil }
}

private func rightRotate(_ x: SNode) -> SNode {
    let y = x.left!
    x.left = y.right
    y.right = x
    return y
}

private func leftRotate(_ x: SNode) -> SNode {
    let y = x.right!
    x.right = y.left
    y.left = x
    return y
}

private func splayOp(_ root: SNode?, _ key: Int) -> SNode? {
    guard let root = root else { return nil }
    if root.key == key { return root }
    if key < root.key {
        guard root.left != nil else { return root }
        if key < root.left!.key {
            root.left!.left = splayOp(root.left!.left, key)
            let r = rightRotate(root)
            return r
        } else if key > root.left!.key {
            root.left!.right = splayOp(root.left!.right, key)
            if root.left!.right != nil { root.left = leftRotate(root.left!) }
        }
        return root.left == nil ? root : rightRotate(root)
    } else {
        guard root.right != nil else { return root }
        if key > root.right!.key {
            root.right!.right = splayOp(root.right!.right, key)
            let r = leftRotate(root)
            return r
        } else if key < root.right!.key {
            root.right!.left = splayOp(root.right!.left, key)
            if root.right!.left != nil { root.right = rightRotate(root.right!) }
        }
        return root.right == nil ? root : leftRotate(root)
    }
}

private func insertNode(_ root: SNode?, _ key: Int) -> SNode {
    guard let root = root else { return SNode(key) }
    let r = splayOp(root, key)!
    if r.key == key { return r }
    let node = SNode(key)
    if key < r.key {
        node.right = r
        node.left = r.left
        r.left = nil
    } else {
        node.left = r
        node.right = r.right
        r.right = nil
    }
    return node
}

private func inorderCollect(_ node: SNode?, _ result: inout [Int]) {
    guard let node = node else { return }
    inorderCollect(node.left, &result)
    result.append(node.key)
    inorderCollect(node.right, &result)
}

func splayTree(_ arr: [Int]) -> [Int] {
    var root: SNode? = nil
    for val in arr { root = insertNode(root, val) }
    var result: [Int] = []
    inorderCollect(root, &result)
    return result.sorted()
}

class SplayNode {
    key: number;
    left: SplayNode | null = null;
    right: SplayNode | null = null;
    constructor(key: number) { this.key = key; }
}

function rightRotate(x: SplayNode): SplayNode {
    const y = x.left!;
    x.left = y.right;
    y.right = x;
    return y;
}

function leftRotate(x: SplayNode): SplayNode {
    const y = x.right!;
    x.right = y.left;
    y.left = x;
    return y;
}

function splayOp(root: SplayNode | null, key: number): SplayNode | null {
    if (!root || root.key === key) return root;
    if (key < root.key) {
        if (!root.left) return root;
        if (key < root.left.key) {
            root.left.left = splayOp(root.left.left, key);
            root = rightRotate(root);
        } else if (key > root.left.key) {
            root.left.right = splayOp(root.left.right, key);
            if (root.left.right) root.left = leftRotate(root.left);
        }
        return root.left ? rightRotate(root) : root;
    } else {
        if (!root.right) return root;
        if (key > root.right.key) {
            root.right.right = splayOp(root.right.right, key);
            root = leftRotate(root);
        } else if (key < root.right.key) {
            root.right.left = splayOp(root.right.left, key);
            if (root.right.left) root.right = rightRotate(root.right);
        }
        return root.right ? leftRotate(root) : root;
    }
}

function insertNode(root: SplayNode | null, key: number): SplayNode {
    if (!root) return new SplayNode(key);
    root = splayOp(root, key)!;
    if (root.key === key) return root;
    const node = new SplayNode(key);
    if (key < root.key) {
        node.right = root;
        node.left = root.left;
        root.left = null;
    } else {
        node.left = root;
        node.right = root.right;
        root.right = null;
    }
    return node;
}

function inorderCollect(node: SplayNode | null, result: number[]): void {
    if (!node) return;
    inorderCollect(node.left, result);
    result.push(node.key);
    inorderCollect(node.right, result);
}

export function splayTree(arr: number[]): number[] {
    let root: SplayNode | null = null;
    for (const val of arr) root = insertNode(root, val);
    const result: number[] = [];
    inorderCollect(root, result);
    return result;
}
